package com.example.oidcclient.web;

import com.example.oidcclient.config.OidcProperties;
import com.example.oidcclient.security.*;
import com.example.oidcclient.service.OidcClient;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.util.StringUtils;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.server.ResponseStatusException;
import org.springframework.web.util.UriComponentsBuilder;

import java.security.SecureRandom;
import java.util.Base64;
import java.util.List;
import java.util.Map;

@Controller
public class OidcController {

    public static final String SESSION_ATTR_STATE = "OIDC_STATE";
    public static final String SESSION_ATTR_NONCE = "OIDC_NONCE";

    private final OidcProperties props;
    private final OidcClient oidcClient;
    private final SecureRandom random = new SecureRandom();

    public OidcController(OidcProperties props, OidcClient oidcClient) {
        this.props = props;
        this.oidcClient = oidcClient;
    }

    @GetMapping("/oidc/login")
    public String login(HttpServletRequest request) {
        HttpSession session = request.getSession(true);
        String state = randomString(32);
        String nonce = randomString(32);
        session.setAttribute(SESSION_ATTR_STATE, state);
        session.setAttribute(SESSION_ATTR_NONCE, nonce);

        String authUrl = UriComponentsBuilder
                .fromUriString(props.getAuthorizationEndpoint())
                .queryParam("response_type", "code")
                .queryParam("client_id", props.getClientId())
                .queryParam("redirect_uri", props.getRedirectUri())
                .queryParam("scope", String.join(" ", props.getScopes()))
                .queryParam("state", state)
                .queryParam("nonce", nonce)
                .build(true)
                .toUriString();

        return "redirect:" + authUrl;
    }

    @GetMapping("/oidc/callback")
    public String callback(HttpServletRequest request,
                           @RequestParam(name = "code", required = false) String code,
                           @RequestParam(name = "state", required = false) String state,
                           @RequestParam(name = "error", required = false) String error,
                           @RequestParam(name = "error_description", required = false) String errorDescription) {

        if (StringUtils.hasText(error)) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, error + (StringUtils.hasText(errorDescription) ? (": " + errorDescription) : ""));
        }
        if (!StringUtils.hasText(code) || !StringUtils.hasText(state)) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Missing code/state");
        }

        HttpSession session = request.getSession(false);
        if (session == null) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "No session");
        }

        String expectedState = (String) session.getAttribute(SESSION_ATTR_STATE);
        String expectedNonce = (String) session.getAttribute(SESSION_ATTR_NONCE);
        session.removeAttribute(SESSION_ATTR_STATE);
        session.removeAttribute(SESSION_ATTR_NONCE);

        if (!StringUtils.hasText(expectedState) || !expectedState.equals(state)) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid state");
        }

        OidcClient.TokenResponse tokenResponse = oidcClient.exchangeCodeForTokens(code);

        Map<String, Object> idClaims = oidcClient.parseAndValidateIdToken(tokenResponse.idToken(), expectedNonce);

        String sub = asString(idClaims.get("sub"));
        String preferredUsername = asString(idClaims.get("preferred_username"));
        String email = asString(idClaims.get("email"));
        String name = asString(idClaims.get("name"));

        if (!StringUtils.hasText(preferredUsername)) preferredUsername = email;
        if (!StringUtils.hasText(preferredUsername)) preferredUsername = sub;

        OidcSession oidcSession = new OidcSession(
                sub,
                preferredUsername,
                email,
                name,
                idClaims,
                tokenResponse.idToken(),
                tokenResponse.accessToken(),
                tokenResponse.refreshToken(),
                tokenResponse.expiresAt()
        );

        OidcAuthenticationToken authentication = new OidcAuthenticationToken(
                preferredUsername,
                oidcSession,
                List.of(new SimpleGrantedAuthority("ROLE_USER"))
        );

        SecurityContextHolder.getContext().setAuthentication(authentication);

        return "redirect:/";
    }

    private String randomString(int bytes) {
        byte[] b = new byte[bytes];
        random.nextBytes(b);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(b);
    }

    private static String asString(Object v) {
        return v == null ? null : String.valueOf(v);
    }
}

package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProperties;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.nimbusds.jose.JOSEException;
import com.nimbusds.jose.JWSAlgorithm;
import com.nimbusds.jose.JWSHeader;
import com.nimbusds.jose.crypto.MACVerifier;
import com.nimbusds.jose.crypto.RSASSAVerifier;
import com.nimbusds.jose.jwk.JWK;
import com.nimbusds.jose.jwk.JWKSet;
import com.nimbusds.jose.jwk.OctetSequenceKey;
import com.nimbusds.jose.jwk.RSAKey;
import com.nimbusds.jwt.JWTClaimsSet;
import com.nimbusds.jwt.SignedJWT;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.util.StringUtils;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.text.ParseException;
import java.time.Instant;
import java.util.*;

@Service
public class OidcClient {

    public record TokenResponse(String tokenType, String accessToken, String idToken, String refreshToken, Instant expiresAt, Map<String, Object> raw) {}

    private final OidcProperties props;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    private volatile JWKSet cachedJwks;
    private volatile Instant jwksFetchedAt;

    public OidcClient(OidcProperties props, ObjectMapper objectMapper) {
        this.props = props;
        this.objectMapper = objectMapper;
        this.restTemplate = new RestTemplate();
    }

    public TokenResponse exchangeCodeForTokens(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", props.getRedirectUri());
        form.add("client_id", props.getClientId());
        if (StringUtils.hasText(props.getClientSecret())) {
            form.add("client_secret", props.getClientSecret());
        }

        HttpEntity<MultiValueMap<String, String>> entity = new HttpEntity<>(form, headers);
        ResponseEntity<String> resp = restTemplate.exchange(URI.create(props.getTokenEndpoint()), HttpMethod.POST, entity, String.class);

        if (!resp.getStatusCode().is2xxSuccessful() || resp.getBody() == null) {
            throw new IllegalStateException("Token endpoint error: " + resp.getStatusCode());
        }

        Map<String, Object> json;
        try {
            json = objectMapper.readValue(resp.getBody(), new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse token response", e);
        }

        String tokenType = asString(json.get("token_type"));
        String accessToken = asString(json.get("access_token"));
        String idToken = asString(json.get("id_token"));
        String refreshToken = asString(json.get("refresh_token"));
        Number expiresIn = asNumber(json.get("expires_in"));
        Instant expiresAt = expiresIn == null ? null : Instant.now().plusSeconds(expiresIn.longValue());

        if (!StringUtils.hasText(idToken)) throw new IllegalStateException("Missing id_token");
        if (!StringUtils.hasText(accessToken)) throw new IllegalStateException("Missing access_token");

        return new TokenResponse(tokenType, accessToken, idToken, refreshToken, expiresAt, Collections.unmodifiableMap(json));
    }

    public Map<String, Object> parseAndValidateIdToken(String idToken, String expectedNonce) {
        SignedJWT jwt;
        try {
            jwt = SignedJWT.parse(idToken);
        } catch (ParseException e) {
            throw new IllegalStateException("Invalid id_token", e);
        }

        JWTClaimsSet claims;
        try {
            claims = jwt.getJWTClaimsSet();
        } catch (ParseException e) {
            throw new IllegalStateException("Invalid id_token claims", e);
        }

        validateClaims(claims, expectedNonce);

        JWSHeader header = jwt.getHeader();
        if (header.getAlgorithm() == null) throw new IllegalStateException("Missing alg");

        boolean verified = verifySignature(jwt);
        if (!verified) throw new IllegalStateException("id_token signature verification failed");

        return new LinkedHashMap<>(claims.getClaims());
    }

    private void validateClaims(JWTClaimsSet claims, String expectedNonce) {
        String iss = claims.getIssuer();
        if (!StringUtils.hasText(iss) || (StringUtils.hasText(props.getIssuer()) && !props.getIssuer().equals(iss))) {
            throw new IllegalStateException("Invalid issuer");
        }

        List<String> aud = claims.getAudience();
        if (aud == null || aud.isEmpty() || !aud.contains(props.getClientId())) {
            throw new IllegalStateException("Invalid audience");
        }

        Date exp = claims.getExpirationTime();
        if (exp == null || exp.toInstant().isBefore(Instant.now().minusSeconds(30))) {
            throw new IllegalStateException("Token expired");
        }

        Date nbf = claims.getNotBeforeTime();
        if (nbf != null && nbf.toInstant().isAfter(Instant.now().plusSeconds(30))) {
            throw new IllegalStateException("Token not yet valid");
        }

        if (StringUtils.hasText(expectedNonce)) {
            Object nonce = claims.getClaim("nonce");
            if (nonce == null || !expectedNonce.equals(String.valueOf(nonce))) {
                throw new IllegalStateException("Invalid nonce");
            }
        }
    }

    private boolean verifySignature(SignedJWT jwt) {
        JWSAlgorithm alg = jwt.getHeader().getAlgorithm();
        if (JWSAlgorithm.HS256.equals(alg) || JWSAlgorithm.HS384.equals(alg) || JWSAlgorithm.HS512.equals(alg)) {
            if (!StringUtils.hasText(props.getClientSecret())) {
                throw new IllegalStateException("clientSecret required for HMAC id_tokens");
            }
            try {
                OctetSequenceKey key = new OctetSequenceKey.Builder(props.getClientSecret().getBytes()).build();
                return jwt.verify(new MACVerifier(key.toByteArray()));
            } catch (JOSEException e) {
                throw new IllegalStateException("HMAC verify failed", e);
            }
        }

        if (JWSAlgorithm.RS256.equals(alg) || JWSAlgorithm.RS384.equals(alg) || JWSAlgorithm.RS512.equals(alg)) {
            String kid = jwt.getHeader().getKeyID();
            JWKSet jwkSet = getJwks();
            List<JWK> matches = kid == null ? jwkSet.getKeys() : jwkSet.getKeys().stream().filter(k -> kid.equals(k.getKeyID())).toList();
            for (JWK jwk : matches) {
                if (jwk instanceof RSAKey rsaKey) {
                    try {
                        return jwt.verify(new RSASSAVerifier(rsaKey.toRSAPublicKey()));
                    } catch (Exception ignored) {
                    }
                }
            }
            return false;
        }

        throw new IllegalStateException("Unsupported alg: " + alg);
    }

    private JWKSet getJwks() {
        Instant now = Instant.now();
        if (cachedJwks != null && jwksFetchedAt != null && jwksFetchedAt.plusSeconds(300).isAfter(now)) {
            return cachedJwks;
        }

        String jwksUri = deriveJwksUriFromIssuer(props.getIssuer());
        if (!StringUtils.hasText(jwksUri)) {
            throw new IllegalStateException("Unable to determine jwks_uri. Provide issuer that supports /.well-known/openid-configuration.");
        }

        ResponseEntity<String> resp = restTemplate.getForEntity(URI.create(jwksUri), String.class);
        if (!resp.getStatusCode().is2xxSuccessful() || resp.getBody() == null) {
            throw new IllegalStateException("JWKS fetch failed: " + resp.getStatusCode());
        }

        try {
            cachedJwks = JWKSet.parse(resp.getBody());
            jwksFetchedAt = now;
            return cachedJwks;
        } catch (ParseException e) {
            throw new IllegalStateException("Invalid JWKS", e);
        }
    }

    private String deriveJwksUriFromIssuer(String issuer) {
        if (!StringUtils.hasText(issuer)) return null;

        String wellKnown = issuer.endsWith("/") ? issuer + ".well-known/openid-configuration"
                : issuer + "/.well-known/openid-configuration";

        ResponseEntity<String> resp;
        try {
            resp = restTemplate.getForEntity(URI.create(wellKnown), String.class);
        } catch (Exception e) {
            return null;
        }

        if (!resp.getStatusCode().is2xxSuccessful() || resp.getBody() == null) return null;

        try {
            Map<String, Object> json = objectMapper.readValue(resp.getBody(), new TypeReference<Map<String, Object>>() {});
            return asString(json.get("jwks_uri"));
        } catch (Exception e) {
            return null;
        }
    }

    private static String asString(Object v) {
        return v == null ? null : String.valueOf(v);
    }

    private static Number asNumber(Object v) {
        if (v instanceof Number n) return n;
        if (v instanceof String s && StringUtils.hasText(s)) {
            try { return Long.parseLong(s); } catch (Exception ignored) {}
        }
        return null;
    }
}

package com.example.oidcclient.web;

import com.example.oidcclient.security.OidcAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ResponseBody;

import java.util.LinkedHashMap;
import java.util.Map;

@Controller
public class HomeController {

    @GetMapping("/")
    @ResponseBody
    public Map<String, Object> home() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        Map<String, Object> out = new LinkedHashMap<>();
        out.put("authenticated", auth != null && auth.isAuthenticated() && !(auth.getPrincipal() instanceof String s && "anonymousUser".equals(s)));
        out.put("name", auth == null ? null : auth.getName());
        if (auth instanceof OidcAuthenticationToken oat) {
            out.put("subject", oat.getSession().getSubject());
            out.put("email", oat.getSession().getEmail());
            out.put("claims", oat.getSession().getIdTokenClaims());
        }
        out.put("login", "/oidc/login");
        out.put("logout", "/logout");
        return out;
    }
}

